// 飞书消息回调(明文)解析 + 口令校验
// 发布给朋友前：把 SECRET 改成你自己的口令
const SECRET = '<analysis>';

let body = $json.body ?? $json;
// n8n 可能把 POST JSON 放在 body 字符串里，需解析后才能读到 challenge
if (typeof body === 'string') {
  try {
    body = JSON.parse(body);
  } catch (e) {
    body = {};
  }
}

// URL 验证：飞书会 POST type=url_verification 并带 challenge（与业务事件的 body 结构不同）
if (body?.type === 'url_verification' && body?.challenge) {
  return [{ json: { kind: 'verification', challenge: body.challenge } }];
}
// 兼容：仅 challenge、无 type 时也视为校验
if (body?.challenge) {
  return [{ json: { kind: 'verification', challenge: body.challenge } }];
}

const event = body?.event ?? body?.data?.event;
const header = body?.header ?? body?.data?.header;
const eventType = header?.event_type;

const openId = event?.sender?.sender_id?.open_id;
const msgType = event?.message?.message_type;
const rawContent = event?.message?.content;

let text = '';
try {
  if (typeof rawContent === 'string') {
    const parsed = JSON.parse(rawContent);
    text = parsed?.text ?? '';
  }
} catch (e) {
  text = '';
}

if (!openId) {
  return [{ json: { kind: 'error', error: '未获取到 open_id（请确认启用私聊消息事件）' } }];
}

// 不是消息事件就忽略（避免误触发）
if (eventType && eventType !== 'im.message.receive_v1') {
  return [{ json: { kind: 'ignore', open_id: openId, reason: 'not_message_event', event_type: eventType } }];
}

if (msgType !== 'text') {
  return [{ json: { kind: 'reject', open_id: openId, error: '目前只支持文本消息（text）' } }];
}

const trimmed = (text || '').trim();
if (!trimmed) {
  return [{ json: { kind: 'reject', open_id: openId, error: '消息为空，请发送：<口令> 空格 <需求>' } }];
}

// 口令格式：<口令> 空格 <需求>
const firstSpace = trimmed.indexOf(' ');
const provided = firstSpace === -1 ? trimmed : trimmed.slice(0, firstSpace);
const idea = firstSpace === -1 ? '' : trimmed.slice(firstSpace + 1).trim();

if (provided !== SECRET) {
  return [{ json: { kind: 'reject', open_id: openId, error: '口令不正确。请发送：<口令> 空格 <需求>' } }];
}
if (!idea) {
  return [{ json: { kind: 'reject', open_id: openId, error: '缺少需求内容。请发送：<口令> 空格 <需求>' } }];
}

return [{ json: { kind: 'ok', open_id: openId, chatInput: idea } }];

const text = $json.message?.content || $json.choices?.[0]?.message?.content;
if (!text) throw new Error('OpenAI 未返回内容');
const match = text.match(/\{[\s\S]*\}/);
if (!match) throw new Error('未找到JSON，原始返回：' + text);
return [{ json: JSON.parse(match[0]) }];

