const text = $json.message?.content || $json.choices?.[0]?.message?.content;
if (!text) throw new Error('报告生成失败，未返回内容');
return [{ json: { output: text } }];

// 飞书要用 interactive 卡片里的 markdown 组件，客户端才会渲染 Markdown（msg_type=text/post 的 md 在部分端上易退化成纯文本）
const md = $json.output;
if (typeof md !== 'string' || !md.trim()) {
  throw new Error('报告内容为空，无法发送飞书卡片');
}
// 卡片/富文本单条 content 有体积上限（约 30KB），超长截断避免接口 400
const maxLen = 28000;
let bodyMd = md;
if (bodyMd.length > maxLen) {
  bodyMd = md.slice(0, maxLen) + '\n\n*(内容过长已截断，请缩短需求或分段分析)*';
}
const card = {
  schema: '2.0',
  body: {
    direction: 'vertical',
    padding: '12px 12px 12px 12px',
    elements: [
      {
        tag: 'markdown',
        content: bodyMd,
        text_align: 'left',
        text_size: 'normal_v2',
        margin: '0px 0px 0px 0px',
      },
    ],
  },
  header: {
    title: { tag: 'plain_text', content: '需求可行性分析' },
    subtitle: { tag: 'plain_text', content: '' },
    template: 'blue',
    padding: '12px 12px 12px 12px',
  },
};
return [{ json: { feishuInteractiveContent: JSON.stringify(card) } }];

